/**
 * GTFS Shape loader & PT-leg geometry enrichment.
 *
 * Loads pre-extracted GTFS shapes (from shapes.json + route_shapes.json) and
 * provides helpers to:
 *  - look up the best matching shape for a PT leg (by route_id + stop coords)
 *  - clip a shape to a boarding→alighting segment
 *
 * Data files are generated by scripts/extract_shapes.py.
 */

let shapesData = null;        // shape_key → [[lat,lon], ...]
let routeShapesData = null;   // feed_id → { route_id → [shape_key, ...] }
let loadPromise = null;

/**
 * Lazily load both JSON files on first use.
 */
export function loadShapes() {
    if (loadPromise) return loadPromise;
    loadPromise = Promise.all([
        fetch('/shapes.json').then(r => r.json()),
        fetch('/route_shapes.json').then(r => r.json()),
    ]).then(([shapes, routeShapes]) => {
        shapesData = shapes;
        routeShapesData = routeShapes;
        const n = Object.keys(shapes).length;
        console.log(`[Shapes] Loaded ${n} GTFS shapes`);
    }).catch(err => {
        console.warn('[Shapes] Failed to load shape data:', err.message);
        loadPromise = null;  // allow retry
    });
    return loadPromise;
}

/**
 * Squared distance between two [lat, lon] points.
 * Only used for nearest-point comparisons, so no need for Haversine.
 */
function distSq(a, b) {
    const dlat = a[0] - b[0];
    const dlon = a[1] - b[1];
    return dlat * dlat + dlon * dlon;
}

/**
 * Find the index of the shape point closest to a given [lat, lon].
 */
function nearestIndex(shape, point) {
    let bestIdx = 0;
    let bestDist = Infinity;
    for (let i = 0; i < shape.length; i++) {
        const d = distSq(shape[i], point);
        if (d < bestDist) {
            bestDist = d;
            bestIdx = i;
        }
    }
    return bestIdx;
}

/**
 * Look up the best shape for a PT leg and clip it to the boarding→alighting stops.
 *
 * @param {string} feedId   – "gtfs_0", "gtfs_1", etc.
 * @param {string} routeId  – GTFS route_id
 * @param {{lat:number, lon:number}} fromStop – boarding stop coords
 * @param {{lat:number, lon:number}} toStop   – alighting stop coords
 * @returns {Array<[number,number]>|null} Clipped [[lat,lon], ...] or null
 */
export function getShapeForLeg(feedId, routeId, fromStop, toStop) {
    if (!shapesData || !routeShapesData) return null;

    const feedRoutes = routeShapesData[feedId];
    if (!feedRoutes) return null;

    const shapeKeys = feedRoutes[routeId];
    if (!shapeKeys || shapeKeys.length === 0) return null;

    const fromPt = [fromStop.lat, fromStop.lon];
    const toPt   = [toStop.lat,   toStop.lon];

    // Try each candidate shape for this route and pick the one whose
    // from-stop nearest-point is closest (best match for this trip variant).
    let bestShape = null;
    let bestFromIdx = 0;
    let bestToIdx = 0;
    let bestFromDist = Infinity;

    for (const key of shapeKeys) {
        const shape = shapesData[key];
        if (!shape || shape.length < 2) continue;

        const fromIdx = nearestIndex(shape, fromPt);
        const toIdx   = nearestIndex(shape, toPt);

        // Shape must go from→to in sequence order (not reversed)
        if (fromIdx >= toIdx) continue;

        const d = distSq(shape[fromIdx], fromPt);
        if (d < bestFromDist) {
            bestFromDist = d;
            bestShape = shape;
            bestFromIdx = fromIdx;
            bestToIdx = toIdx;
        }
    }

    if (!bestShape) {
        // Fallback: maybe the shape runs in the other direction
        // (all candidates had fromIdx >= toIdx). Try reversing the clip.
        for (const key of shapeKeys) {
            const shape = shapesData[key];
            if (!shape || shape.length < 2) continue;

            const fromIdx = nearestIndex(shape, fromPt);
            const toIdx   = nearestIndex(shape, toPt);

            if (fromIdx <= toIdx) continue;  // would have matched above

            const d = distSq(shape[fromIdx], fromPt);
            if (d < bestFromDist) {
                bestFromDist = d;
                bestShape = shape;
                bestFromIdx = toIdx;    // swap
                bestToIdx = fromIdx;    // swap
            }
        }
    }

    if (!bestShape) return null;

    // Clip: include both endpoints, and prepend/append the actual stop coords
    // for a seamless connection with adjacent walk legs.
    const clipped = bestShape.slice(bestFromIdx, bestToIdx + 1);
    if (clipped.length === 0) return null;

    // Replace first & last with exact stop coordinates (avoid tiny gap)
    clipped[0] = [fromStop.lat, fromStop.lon];
    clipped[clipped.length - 1] = [toStop.lat, toStop.lon];

    return clipped;
}

/**
 * Check whether shape data has been loaded.
 */
export function shapesLoaded() {
    return shapesData !== null && routeShapesData !== null;
}
